-- The runtime surface drizzle cannot declare: extensions, forced row security so the
-- owner role cannot bypass the scope lattice, the vchord_bm25 lexical lane, and the
-- ontology seed catalog the extraction gate reads.
ALTER TABLE document FORCE ROW LEVEL SECURITY;--> statement-breakpoint
ALTER TABLE chunk FORCE ROW LEVEL SECURITY;--> statement-breakpoint
ALTER TABLE entity_content FORCE ROW LEVEL SECURITY;--> statement-breakpoint
ALTER TABLE entity_claim FORCE ROW LEVEL SECURITY;--> statement-breakpoint
ALTER TABLE fact_content FORCE ROW LEVEL SECURITY;--> statement-breakpoint
ALTER TABLE fact_claim FORCE ROW LEVEL SECURITY;--> statement-breakpoint
ALTER TABLE community FORCE ROW LEVEL SECURITY;--> statement-breakpoint
ALTER TABLE profile FORCE ROW LEVEL SECURITY;--> statement-breakpoint
ALTER TABLE session_item FORCE ROW LEVEL SECURITY;--> statement-breakpoint
ALTER TABLE watermark FORCE ROW LEVEL SECURITY;--> statement-breakpoint
SELECT tokenizer_catalog.create_tokenizer('aizk_bm25', $$
model = "llmlingua2"
$$);--> statement-breakpoint
CREATE FUNCTION chunk_bm25_sync() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN NEW.bm25 := tokenizer_catalog.tokenize(coalesce(NEW.lexical, NEW.text), 'aizk_bm25'); RETURN NEW; END; $$;--> statement-breakpoint
CREATE TRIGGER chunk_bm25_sync BEFORE INSERT OR UPDATE OF text, lexical ON chunk FOR EACH ROW EXECUTE FUNCTION chunk_bm25_sync();--> statement-breakpoint
CREATE INDEX ix_chunk_bm25 ON chunk USING bm25 (bm25 bm25_catalog.bm25_ops);--> statement-breakpoint
GRANT USAGE ON SCHEMA public TO aizk_app;--> statement-breakpoint
GRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO aizk_app;--> statement-breakpoint
ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO aizk_app;--> statement-breakpoint
GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO aizk_app;--> statement-breakpoint
GRANT USAGE ON SCHEMA tokenizer_catalog TO aizk_app;--> statement-breakpoint
GRANT USAGE ON SCHEMA bm25_catalog TO aizk_app;--> statement-breakpoint
